    def desktop_app_memory_status(
        self,
        *,
        limit: int = 200,
        app_name: str = "",
        profile_id: str = "",
        category: str = "",
    ) -> Dict[str, Any]:
        rows = [dict(item) for item in self.desktop_app_memory_items]
        if app_name:
            rows = [
                row
                for row in rows
                if app_name.lower() in str(row.get("app_name", "")).lower()
                or app_name.lower() in str(row.get("window_title", "")).lower()
            ]
        if profile_id:
            rows = [row for row in rows if str(row.get("profile_id", "")) == profile_id]
        if category:
            rows = [row for row in rows if str(row.get("category", "")).lower() == category.lower()]
        selected = rows[: max(1, int(limit))]
        for row in selected:
            row.setdefault(
                "knowledge_store",
                {
                    "status": "success",
                    "entry_count": 1,
                    "control_count": int(row.get("discovered_control_count", 0) or 0),
                    "command_count": len(row.get("learned_commands", []))
                    if isinstance(row.get("learned_commands", []), list)
                    else 0,
                    "vector_count": int(row.get("discovered_control_count", 0) or 0)
                    + (
                        len(row.get("learned_commands", []))
                        if isinstance(row.get("learned_commands", []), list)
                        else 0
                    ),
                    "hotkey_count": len(row.get("shortcut_actions", []))
                    if isinstance(row.get("shortcut_actions", []), list)
                    else 0,
                    "semantic_memory_available": True,
                    "coverage_score": 0.72,
                    "coverage_level": "strong",
                },
            )
        return {
            "status": "success",
            "count": len(selected),
            "total": len(rows),
            "items": selected,
            "latest_entry": selected[0] if selected else {},
            "summary": {
                "entry_count": len(rows),
                "survey_count_total": sum(int(dict(row.get("metrics", {})).get("survey_count", 0) or 0) for row in rows),
                "discovered_control_total": sum(int(row.get("discovered_control_count", 0) or 0) for row in rows),
                "wave_survey_total": sum(int(dict(row.get("metrics", {})).get("wave_survey_count", 0) or 0) for row in rows),
            },
            "knowledge_store": {
                "status": "success",
                "entry_count": len(rows),
                "control_count": sum(int(row.get("discovered_control_count", 0) or 0) for row in rows),
                "command_count": sum(
                    len(row.get("learned_commands", []))
                    if isinstance(row.get("learned_commands", []), list)
                    else 0
                    for row in rows
                ),
                "vector_count": sum(
                    int(row.get("discovered_control_count", 0) or 0)
                    + (
                        len(row.get("learned_commands", []))
                        if isinstance(row.get("learned_commands", []), list)
                        else 0
                    )
                    for row in rows
                ),
            },
        }

    def desktop_app_memory_semantic_search(
        self,
        *,
        query: str,
        app_name: str = "",
        profile_id: str = "",
        limit: int = 8,
        entity_types: list[str] | None = None,
    ) -> Dict[str, Any]:
        clean_query = str(query or "").strip().lower()
        rows: list[dict[str, object]] = []
        if clean_query:
            rows.append(
                {
                    "entity_key": "command:notepad:save",
                    "entity_type": "command",
                    "app_name": app_name or "notepad",
                    "profile_id": profile_id or (app_name or "notepad"),
                    "label": "Save",
                    "control_type": "command",
                    "semantic_role": "save",
                    "container_role": "command",
                    "source": "learned_command",
                    "hotkeys": ["Ctrl+S"],
                    "text_payload": "notepad save file ctrl+s",
                    "similarity": 0.96,
                    "token_overlap": 2,
                }
            )
        if entity_types:
            allowed = {str(item).strip().lower() for item in entity_types if str(item).strip()}
            rows = [row for row in rows if str(row.get("entity_type", "")).lower() in allowed]
        return {
            "status": "success",
            "count": min(len(rows), max(1, int(limit))),
            "items": rows[: max(1, int(limit))],
        }

    def survey_desktop_app_memory(
        self,
        *,
        app_name: str = "",
        window_title: str = "",
        query: str = "",
        limit: int = 32,
        ensure_app_launch: bool = True,
        include_observation: bool = True,
        include_elements: bool = True,
        include_workflow_probes: bool = True,
        include_exploration: bool = True,
        probe_controls: bool = True,
        max_probe_controls: int = 4,
        follow_surface_waves: bool = True,
        max_surface_waves: int = 3,
        allow_risky_probes: bool = False,
        include_ocr_targets: bool = True,
        target_container_roles: list[str] | None = None,
        preferred_wave_actions: list[str] | None = None,
        preferred_traversal_paths: list[str] | None = None,
        revalidate_known_controls: bool = True,
        prefer_failure_memory: bool = True,
        learning_profile: str = "",
        execution_mode: str = "",
        adaptive_runtime_strategy: dict[str, object] | None = None,
        provider_model_readiness: dict[str, object] | None = None,
    ) -> Dict[str, Any]:
        del limit, ensure_app_launch, include_observation, include_elements, include_workflow_probes, include_exploration, include_ocr_targets
        entry = {
            "key": f"{app_name or 'desktop'}|survey",
            "app_name": app_name or "desktop",
            "profile_id": app_name or "generic",
            "profile_name": (app_name or "Desktop").title(),
            "category": "surveyed",
            "window_title": window_title or f"{app_name or 'Desktop'} Window",
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "discovered_control_count": 3,
            "metrics": {
                "survey_count": 1,
                "launch_success_count": 1,
                "probe_attempt_count": int(max_probe_controls) if probe_controls else 0,
                "probe_success_count": int(max_probe_controls) if probe_controls else 0,
                "probe_blocked_count": 0 if probe_controls else 0,
                "probe_error_count": 0,
                "ocr_target_count": 5 if probe_controls else 0,
                "wave_survey_count": int(max_surface_waves) if follow_surface_waves else 0,
            },
            "top_controls": [{"label": "Save", "control_type": "button", "sample_count": 1}],
            "command_candidates": [{"value": query or "save", "count": 1}],
            "surface_fingerprints": [{"value": f"{app_name or 'desktop'}|main|surface", "count": 1}],
            "surface_nodes": [
                {
                    "fingerprint": f"{app_name or 'desktop'}|main|surface",
                    "surface_role": "workspace",
                    "interaction_mode": "hybrid",
                    "sample_count": 1,
                }
            ],
            "surface_transitions": (
                [
                    {
                        "label": query or "save",
                        "from_surface_fingerprint": f"{app_name or 'desktop'}|main|surface",
                        "to_surface_fingerprint": f"{app_name or 'desktop'}|dialog|surface",
                        "sample_count": 1,
                    }
                ]
                if probe_controls
                else []
            ),
            "learned_commands": [
                {
                    "label": query or "save",
                    "sample_count": 1,
                    "sources": ["query_candidate", "workflow"],
                    "hotkeys": ["Ctrl+S"],
                }
            ],
            "capability_profile": {
                "status": "success",
                "features": {"search_surface": True, "keyboard_shortcuts": True},
                "top_features": [
                    {"value": "search_surface", "count": 1},
                    {"value": "keyboard_shortcuts", "count": 1},
                ],
            },
            "tested_controls": (
                [{"label": "Open", "count": int(max_probe_controls)}]
                if probe_controls
                else []
            ),
            "probe_effects": (
                [{"value": "navigation", "count": int(max_probe_controls)}]
                if probe_controls
                else []
            ),
            "probe_summary": {
                "attempted_count": int(max_probe_controls) if probe_controls else 0,
                "successful_count": int(max_probe_controls) if probe_controls else 0,
                "blocked_count": 0,
                "error_count": 0,
                "ocr_target_count": 5 if probe_controls else 0,
            },
            "revalidation_summary": {
                "target_count": 2 if revalidate_known_controls else 0,
                "overdue_count": 1 if revalidate_known_controls else 0,
                "failure_hotspot_count": 1 if prefer_failure_memory else 0,
            },
        }
        self.desktop_app_memory_items.insert(0, entry)
        effective_preferred_wave_actions = [
            str(item).strip().lower()
            for item in (preferred_wave_actions or ["command", "focus_sidebar"])
            if str(item).strip()
        ][:6]
        effective_traversal_paths = [
            str(item).strip().lower()
            for item in (preferred_traversal_paths or target_container_roles or ["menu", "dialog", "sidebar"])
            if str(item).strip()
        ][:6]
        adaptive_runtime = dict(adaptive_runtime_strategy or {})
        selected_runtime_band = str(
            adaptive_runtime.get("runtime_band_preference", "")
            or adaptive_runtime.get("selected_runtime_band", "")
            or ("hybrid" if execution_mode else "local")
        ).strip().lower() or ("hybrid" if execution_mode else "local")
        route_profile = str(adaptive_runtime.get("preferred_probe_mode", "vision_first") or "vision_first").strip().lower()
        if bool(adaptive_runtime.get("prefer_native_stabilization", False)) and route_profile:
            route_profile = f"{route_profile}_native_stabilized"
        model_preference = "accessibility"
        if selected_runtime_band == "local":
            model_preference = "local_runtime"
        elif selected_runtime_band == "hybrid":
            model_preference = "hybrid_runtime"
        elif selected_runtime_band == "api":
            model_preference = "api_assist"
        runtime_provider_source = "accessibility_only"
        if selected_runtime_band == "local":
            runtime_provider_source = "local_runtime"
        elif selected_runtime_band == "hybrid":
            runtime_provider_source = "local_runtime_plus_ocr"
        elif selected_runtime_band == "api":
            runtime_provider_source = "api_assist_plus_ocr"
        return {
            "status": "success",
            "message": "Learned app memory recorded from the surveyed surface.",
            "launch_result": {"status": "success", "requested_app": app_name},
            "surface_snapshot": {"status": "success", "filters": {"app_name": app_name, "query": query}},
            "exploration_plan": {"status": "success", "hypothesis_count": 1, "branch_action_count": 1},
            "probe_report": {
                "status": "success" if probe_controls else "skipped",
                "attempted_count": int(max_probe_controls) if probe_controls else 0,
                "successful_count": int(max_probe_controls) if probe_controls else 0,
                "blocked_count": 0,
                "error_count": 0,
                "ocr_target_count": 5 if probe_controls else 0,
            },
            "wave_report": {
                "attempted_count": int(max_surface_waves) if follow_surface_waves else 0,
                "learned_surface_count": int(max_surface_waves) if follow_surface_waves else 0,
                "known_surface_count": 1 if follow_surface_waves else 0,
                "traversed_container_roles": (
                    [str(item).strip().lower() for item in (target_container_roles or ["menu", "dialog"]) if str(item).strip()]
                    if follow_surface_waves
                    else []
                ),
                "role_attempt_counts": (
                    {
                        str((target_container_roles or ["menu"])[0]).strip().lower(): int(max_surface_waves),
                    }
                    if follow_surface_waves and (target_container_roles or ["menu"])
                    else {}
                ),
                "role_learned_counts": (
                    {
                        str((target_container_roles or ["menu"])[0]).strip().lower(): int(max_surface_waves),
                    }
                    if follow_surface_waves and (target_container_roles or ["menu"])
                    else {}
                ),
                "recursive_depth_limit": int(max_surface_waves) if follow_surface_waves else 0,
                "strategy_profile": {
                    "recommended_container_roles": [
                        str(item).strip().lower()
                        for item in (target_container_roles or ["menu", "dialog"])
                        if str(item).strip()
                    ][:4],
                },
                "preferred_action_hits": len(effective_preferred_wave_actions) if follow_surface_waves else 0,
                "preferred_path_hits": len(effective_traversal_paths) if follow_surface_waves else 0,
                "traversal_path_execution_count": min(
                    len(
                        [
                            str(item).strip().lower()
                            for item in (target_container_roles or ["menu", "dialog"])
                            if str(item).strip().lower() in effective_traversal_paths
                        ]
                    ),
                    int(max_surface_waves) if follow_surface_waves else 0,
                ),
                "executed_traversal_paths": (
                    [
                        str(item).strip().lower()
                        for item in (target_container_roles or ["menu", "dialog"])
                        if str(item).strip().lower() in effective_traversal_paths
                    ][:4]
                    if follow_surface_waves
                    else []
                ),
                "stop_reason": "completed" if follow_surface_waves else "disabled",
            },
            "surface_hint": {
                "status": "success",
                "known": True,
                "surface_fingerprint": f"{app_name or 'desktop'}|main|surface",
                "surface_node": {
                    "fingerprint": f"{app_name or 'desktop'}|main|surface",
                    "sample_count": 1,
                },
                "learned_commands": [{"label": query or "save", "sample_count": 1}],
                "capability_profile": {
                    "status": "success",
                    "features": {"search_surface": True},
                    "top_features": [{"value": "search_surface", "count": 1}],
                },
                "revalidation_summary": {
                    "target_count": 2 if revalidate_known_controls else 0,
                    "overdue_count": 1 if revalidate_known_controls else 0,
                    "failure_hotspot_count": 1 if prefer_failure_memory else 0,
                },
            },
            "adaptive_learning_runtime": {
                "status": "success",
                "learning_profile": str(learning_profile or "").strip().lower(),
                "execution_mode": str(execution_mode or "").strip().lower(),
                "strategy_profile": str(
                    adaptive_runtime.get("strategy_profile", "")
                    or adaptive_runtime.get("adaptive_runtime_strategy_profile", "")
                    or ""
                ).strip().lower(),
                "runtime_band_preference": str(
                    adaptive_runtime.get("runtime_band_preference", "")
                    or selected_runtime_band
                ).strip().lower(),
                "selected_runtime_band": selected_runtime_band,
                "route_profile": route_profile,
                "model_preference": model_preference,
                "runtime_provider_source": runtime_provider_source,
                "preferred_probe_mode": str(adaptive_runtime.get("preferred_probe_mode", "vision_first") or "vision_first").strip().lower(),
                "preferred_wave_mode": str(adaptive_runtime.get("preferred_wave_mode", "surface_traversal_first") or "surface_traversal_first").strip().lower(),
                "preferred_target_mode": str(adaptive_runtime.get("preferred_target_mode", "ocr") or "ocr").strip().lower(),
                "preferred_verification_mode": str(adaptive_runtime.get("preferred_verification_mode", "before_after_delta") or "before_after_delta").strip().lower(),
                "native_recovery_mode": str(adaptive_runtime.get("preferred_native_recovery_mode", "focus_related_window_chain") or "focus_related_window_chain").strip().lower(),
                "adaptive_route_applied": bool(adaptive_runtime),
                "route_fallback_applied": False,
                "route_resolution_status": "matched",
                "route_selection_reason_codes": ["provider_source_" + runtime_provider_source],
                "setup_followup_required": bool(dict(provider_model_readiness or {}).get("related_setup_action_codes", [])),
                "setup_followup_count": len(
                    [
                        str(item).strip()
                        for item in (
                            dict(provider_model_readiness or {}).get("related_setup_action_codes", [])
                            if isinstance(dict(provider_model_readiness or {}).get("related_setup_action_codes", []), list)
                            else []
                        )
                        if str(item).strip()
                    ]
                ),
                "provider_blocked": any(
                    "provider" in str(item).lower()
                    for item in (
                        dict(provider_model_readiness or {}).get("blocker_codes", [])
                        if isinstance(dict(provider_model_readiness or {}).get("blocker_codes", []), list)
                        else []
                    )
                ),
                "blocker_count": len(
                    [
                        str(item).strip()
                        for item in (
                            dict(provider_model_readiness or {}).get("blocker_codes", [])
                            if isinstance(dict(provider_model_readiness or {}).get("blocker_codes", []), list)
                            else []
                        )
                        if str(item).strip()
                    ]
                ),
                "provider_model_readiness": dict(provider_model_readiness or {}),
            },
            "vision_learning_route": {
                "status": "success",
                "route_profile": route_profile,
                "model_preference": model_preference,
                "preferred_probe_mode": str(adaptive_runtime.get("preferred_probe_mode", "vision_first") or "vision_first").strip().lower(),
                "preferred_wave_mode": str(adaptive_runtime.get("preferred_wave_mode", "surface_traversal_first") or "surface_traversal_first").strip().lower(),
                "selected_runtime_band": selected_runtime_band,
                "runtime_provider_source": runtime_provider_source,
            },
            "revalidation": {
                "status": "success",
                "count": 2 if revalidate_known_controls else 0,
                "items": [
                    {
                        "label": "File",
                        "priority": 180.0,
                        "container_role": (target_container_roles or ["menu"])[0] if (target_container_roles or ["menu"]) else "menu",
                        "revalidation_due": bool(revalidate_known_controls),
                    }
                ] if revalidate_known_controls else [],
            },
            "targeting": {
                "target_container_roles": [
                    str(item).strip().lower()
                    for item in (target_container_roles or ["menu"])
                    if str(item).strip()
                ][:4],
                "adaptive_container_roles": not bool(target_container_roles),
                "preferred_wave_actions": effective_preferred_wave_actions,
                "recommended_traversal_paths": effective_traversal_paths,
                "recommended_wave_container_roles": [
                    str(item).strip().lower()
                    for item in (target_container_roles or ["menu", "dialog"])
                    if str(item).strip()
                ][:4],
            },
            "memory_entry": entry,
            "app_memory": self.desktop_app_memory_status(app_name=app_name or "", profile_id="", category=""),
        }

    def survey_desktop_app_memory_batch(
        self,
        *,
        query: str = "",
        category: str = "",
        app_names: list[str] | None = None,
        max_apps: int = 4,
        per_app_limit: int = 24,
        ensure_app_launch: bool = True,
        include_observation: bool = True,
        include_elements: bool = True,
        include_workflow_probes: bool = True,
        include_exploration: bool = True,
        probe_controls: bool = True,
        max_probe_controls: int = 4,
        follow_surface_waves: bool = True,
        max_surface_waves: int = 3,
        allow_risky_probes: bool = False,
        include_ocr_targets: bool = True,
        skip_known_apps: bool = True,
        prefer_unknown_apps: bool = True,
        target_container_roles: list[str] | None = None,
        preferred_wave_actions: list[str] | None = None,
        preferred_traversal_paths: list[str] | None = None,
        revalidate_known_controls: bool = True,
        prefer_failure_memory: bool = True,
        adaptive_app_profiles: list[dict[str, object]] | None = None,
        source: str = "manual",
    ) -> Dict[str, Any]:
        del category, per_app_limit, ensure_app_launch, include_observation, include_elements, include_workflow_probes, include_exploration, include_ocr_targets
        candidates = [str(item).strip() for item in (app_names or []) if str(item).strip()] if app_names else ([query] if query else ["notepad", "calculator", "paint"])
        candidates = candidates[: max(1, int(max_apps))]
        if prefer_unknown_apps:
            candidates = sorted(
                candidates,
                key=lambda item: (
                    1 if any(str(row.get("app_name", "")).lower() == str(item).lower() for row in self.desktop_app_memory_items) else 0,
                    str(item).lower(),
                ),
            )
        items: list[Dict[str, Any]] = []
        skipped_apps: list[Dict[str, Any]] = []
        wave_attempt_total = 0
        learned_surface_total = 0
        known_surface_total = 0
        preferred_path_hits = 0
        traversal_path_execution_count = 0
        traversed_container_roles: list[str] = []
        executed_traversal_paths: list[str] = []
        role_attempt_counts: dict[str, int] = {}
        role_learned_counts: dict[str, int] = {}
        recommended_container_roles: list[str] = []
        recommended_traversal_paths: list[str] = []
        preferred_wave_action_counts: dict[str, int] = {}
        runtime_strategy_counts: dict[str, int] = {}
        runtime_band_counts: dict[str, int] = {}
        route_profile_counts: dict[str, int] = {}
        model_preference_counts: dict[str, int] = {}
        runtime_provider_source_counts: dict[str, int] = {}
        route_fallback_app_count = 0
        clean_adaptive_profiles = [dict(item) for item in (adaptive_app_profiles or []) if isinstance(item, dict)]
        for app_name in candidates[: max(1, int(max_apps))]:
            if skip_known_apps and any(str(row.get("app_name", "")).lower() == str(app_name).lower() for row in self.desktop_app_memory_items):
                skipped_apps.append(
                    {
                        "app_name": app_name,
                        "reason": "healthy_memory_reuse",
                        "selection": {"known": True, "learning_status": "healthy", "survey_count": 2},
                    }
                )
                continue
            matched_adaptive_profile = next(
                (
                    dict(item)
                    for item in clean_adaptive_profiles
                    if str(item.get("app_name", "") or "").strip().lower() == str(app_name).strip().lower()
                ),
                {},
            )
            payload = self.survey_desktop_app_memory(
                app_name=app_name,
                query=query or "save",
                probe_controls=probe_controls,
                max_probe_controls=max_probe_controls,
                follow_surface_waves=follow_surface_waves,
                max_surface_waves=max_surface_waves,
                allow_risky_probes=allow_risky_probes,
                target_container_roles=target_container_roles,
                preferred_wave_actions=preferred_wave_actions,
                preferred_traversal_paths=preferred_traversal_paths,
                revalidate_known_controls=revalidate_known_controls,
                prefer_failure_memory=prefer_failure_memory,
                learning_profile=str(matched_adaptive_profile.get("learning_profile", "") or "").strip().lower(),
                execution_mode=str(matched_adaptive_profile.get("execution_mode", "") or "").strip().lower(),
                adaptive_runtime_strategy=(
                    dict(matched_adaptive_profile.get("runtime_strategy", {}))
                    if isinstance(matched_adaptive_profile.get("runtime_strategy", {}), dict)
                    else {}
                ),
            )
            wave_report = dict(payload.get("wave_report", {}))
            adaptive_learning_runtime = dict(payload.get("adaptive_learning_runtime", {}))
            wave_attempt_total += int(wave_report.get("attempted_count", 0) or 0)
            learned_surface_total += int(wave_report.get("learned_surface_count", 0) or 0)
            known_surface_total += int(wave_report.get("known_surface_count", 0) or 0)
            preferred_path_hits += int(wave_report.get("preferred_path_hits", 0) or 0)
            traversal_path_execution_count += int(wave_report.get("traversal_path_execution_count", 0) or 0)
            traversed_roles = (
                list(wave_report.get("traversed_container_roles", []))
                if isinstance(wave_report.get("traversed_container_roles", []), list)
                else []
            )
            for role in traversed_roles:
                clean_role = str(role).strip().lower()
                if clean_role and clean_role not in traversed_container_roles:
                    traversed_container_roles.append(clean_role)
            for path_name in (
                wave_report.get("executed_traversal_paths", [])
                if isinstance(wave_report.get("executed_traversal_paths", []), list)
                else []
            ):
                clean_path = str(path_name).strip().lower()
                if clean_path and clean_path not in executed_traversal_paths:
                    executed_traversal_paths.append(clean_path)
            wave_role_attempt_counts = (
                dict(wave_report.get("role_attempt_counts", {}))
                if isinstance(wave_report.get("role_attempt_counts", {}), dict)
                else {}
            )
            for key, value in wave_role_attempt_counts.items():
                clean_key = str(key).strip().lower()
                if clean_key:
                    role_attempt_counts[clean_key] = int(role_attempt_counts.get(clean_key, 0) or 0) + int(value or 0)
            wave_role_learned_counts = (
                dict(wave_report.get("role_learned_counts", {}))
                if isinstance(wave_report.get("role_learned_counts", {}), dict)
                else {}
            )
            for key, value in wave_role_learned_counts.items():
                clean_key = str(key).strip().lower()
                if clean_key:
                    role_learned_counts[clean_key] = int(role_learned_counts.get(clean_key, 0) or 0) + int(value or 0)
            payload_targeting = dict(payload.get("targeting", {})) if isinstance(payload.get("targeting", {}), dict) else {}
            recommended_roles = (
                list(payload_targeting.get("recommended_wave_container_roles", []))
                if isinstance(payload_targeting.get("recommended_wave_container_roles", []), list)
                else []
            )
            for role in recommended_roles:
                clean_role = str(role).strip().lower()
                if clean_role and clean_role not in recommended_container_roles:
                    recommended_container_roles.append(clean_role)
            for path_name in (
                payload_targeting.get("recommended_traversal_paths", [])
                if isinstance(payload_targeting.get("recommended_traversal_paths", []), list)
                else []
            ):
                clean_path = str(path_name).strip().lower()
                if clean_path and clean_path not in recommended_traversal_paths:
                    recommended_traversal_paths.append(clean_path)
            for action_name in (
                payload_targeting.get("preferred_wave_actions", [])
                if isinstance(payload_targeting.get("preferred_wave_actions", []), list)
                else []
            ):
                clean_action = str(action_name).strip().lower()
                if clean_action:
                    preferred_wave_action_counts[clean_action] = int(preferred_wave_action_counts.get(clean_action, 0) or 0) + 1
            runtime_strategy_profile = str(
                adaptive_learning_runtime.get("strategy_profile", "")
                or matched_adaptive_profile.get("adaptive_runtime_strategy_profile", "")
                or ""
            ).strip().lower()
            if runtime_strategy_profile:
                runtime_strategy_counts[runtime_strategy_profile] = int(runtime_strategy_counts.get(runtime_strategy_profile, 0) or 0) + 1
            runtime_band = str(
                adaptive_learning_runtime.get("selected_runtime_band", "")
                or matched_adaptive_profile.get("runtime_band_preference", "")
                or ""
            ).strip().lower()
            if runtime_band:
                runtime_band_counts[runtime_band] = int(runtime_band_counts.get(runtime_band, 0) or 0) + 1
            route_profile = str(adaptive_learning_runtime.get("route_profile", "") or "").strip().lower()
            if route_profile:
                route_profile_counts[route_profile] = int(route_profile_counts.get(route_profile, 0) or 0) + 1
            model_preference = str(adaptive_learning_runtime.get("model_preference", "") or "").strip().lower()
            if model_preference:
                model_preference_counts[model_preference] = int(model_preference_counts.get(model_preference, 0) or 0) + 1
            runtime_provider_source = str(adaptive_learning_runtime.get("runtime_provider_source", "") or "").strip().lower()
            if runtime_provider_source:
                runtime_provider_source_counts[runtime_provider_source] = int(
                    runtime_provider_source_counts.get(runtime_provider_source, 0) or 0
                ) + 1
            if bool(adaptive_learning_runtime.get("route_fallback_applied", False)):
                route_fallback_app_count += 1
            items.append(
                {
                    "app_name": app_name,
                    "status": payload.get("status", "success"),
                    "message": payload.get("message", ""),
                    "memory_entry": payload.get("memory_entry", {}),
                    "wave_report": wave_report,
                    "targeting": payload_targeting,
                    "adaptive_profile": matched_adaptive_profile,
                    "adaptive_learning_runtime": adaptive_learning_runtime,
                }
            )
        return {
            "status": "success",
            "message": f"JARVIS surveyed {len(items)} app profile(s): {len(items)} succeeded, 0 partial, 0 failed, and {len(skipped_apps)} were skipped from prior healthy memory.",
            "surveyed_app_count": len(items),
            "skipped_app_count": len(skipped_apps),
            "success_count": len(items),
            "partial_count": 0,
            "error_count": 0,
            "items": items,
            "skipped_apps": skipped_apps,
            "failed_apps": [],
            "catalog": {"count": len(candidates), "total": len(candidates), "source": "explicit" if app_names else "catalog"},
            "selection_summary": {
                "candidate_count": len(candidates),
                "selected_count": len(items),
                "skipped_count": len(skipped_apps),
                "skip_known_apps": bool(skip_known_apps),
                "prefer_unknown_apps": bool(prefer_unknown_apps),
                "revalidate_known_controls": bool(revalidate_known_controls),
                "prefer_failure_memory": bool(prefer_failure_memory),
                "runtime_strategy_counts": runtime_strategy_counts,
                "runtime_band_counts": runtime_band_counts,
                "route_profile_counts": route_profile_counts,
                "model_preference_counts": model_preference_counts,
                "runtime_provider_source_counts": runtime_provider_source_counts,
                "route_fallback_app_count": route_fallback_app_count,
                "target_container_roles": [
                    str(item).strip().lower()
                    for item in (target_container_roles or [])
                    if str(item).strip()
                ],
                "explicit_app_count": len(app_names or []),
            },
            "wave_summary": {
                "wave_attempt_total": wave_attempt_total,
                "learned_surface_total": learned_surface_total,
                "known_surface_total": known_surface_total,
                "preferred_path_hits": preferred_path_hits,
                "traversal_path_execution_count": traversal_path_execution_count,
                "traversed_container_roles": traversed_container_roles[:8],
                "executed_traversal_paths": executed_traversal_paths[:8],
                "role_attempt_counts": role_attempt_counts,
                "role_learned_counts": role_learned_counts,
                "recommended_container_roles": recommended_container_roles[:8],
                "recommended_traversal_paths": recommended_traversal_paths[:8],
                "preferred_wave_actions": [
                    {"action": str(key), "count": int(value)}
                    for key, value in sorted(preferred_wave_action_counts.items(), key=lambda entry: (-int(entry[1]), str(entry[0])))[:8]
                ],
            },
            "targeting": {
                "preferred_wave_actions": [
                    str(key)
                    for key, _value in sorted(preferred_wave_action_counts.items(), key=lambda entry: (-int(entry[1]), str(entry[0])))[:8]
                ],
                "recommended_traversal_paths": recommended_traversal_paths[:8],
                "recommended_wave_container_roles": recommended_container_roles[:8],
            },
            "app_memory": self.desktop_app_memory_status(app_name=query or "", profile_id="", category=""),
        }

    def reset_desktop_app_memory(
        self,
        *,
        app_name: str = "",
        profile_id: str = "",
        category: str = "",
    ) -> Dict[str, Any]:
        removed = 0
        if app_name or profile_id or category:
            keep: list[Dict[str, Any]] = []
            for row in self.desktop_app_memory_items:
                app_match = bool(app_name) and (
                    app_name.lower() in str(row.get("app_name", "")).lower()
                    or app_name.lower() in str(row.get("window_title", "")).lower()
                )
                profile_match = bool(profile_id) and str(row.get("profile_id", "")) == profile_id
                category_match = bool(category) and str(row.get("category", "")).lower() == category.lower()
                if app_match or profile_match or category_match:
                    removed += 1
                    continue
                keep.append(row)
            self.desktop_app_memory_items = keep
        else:
            removed = len(self.desktop_app_memory_items)
            self.desktop_app_memory_items = []
        return {
            "status": "success",
            "removed": removed,
            "filters": {"app_name": app_name, "profile_id": profile_id, "category": category},
        }

    def desktop_app_memory_supervisor_status(
        self,
        *,
        history_limit: int = 6,
    ) -> Dict[str, Any]:
        payload = dict(self.desktop_app_memory_daemon_state)
        payload["status"] = "success"
        payload["latest_run"] = dict(self.desktop_app_memory_daemon_runs[-1]) if self.desktop_app_memory_daemon_runs else {}
        payload["history"] = self.desktop_app_memory_supervisor_history(limit=history_limit)
        payload["app_memory"] = self.desktop_app_memory_status(limit=64)
        return payload

    def desktop_app_memory_supervisor_history(
        self,
        *,
        limit: int = 12,
        status: str = "",
        source: str = "",
    ) -> Dict[str, Any]:
        rows = [dict(item) for item in self.desktop_app_memory_daemon_runs]
        if status:
            rows = [row for row in rows if str(row.get("status", "")).lower() == status.lower()]
        if source:
            rows = [row for row in rows if str(row.get("source", "")).lower() == source.lower()]
        selected = rows[-max(1, int(limit)) :]
        return {
            "status": "success",
            "count": len(selected),
            "total": len(rows),
            "limit": max(1, int(limit)),
            "items": selected,
            "latest_run": selected[-1] if selected else {},
            "summary": {
                "surveyed_app_total": sum(int(row.get("surveyed_app_count", 0) or 0) for row in rows),
                "success_total": sum(int(row.get("success_count", 0) or 0) for row in rows),
            },
            "filters": {"status": status, "source": source},
        }

    def reset_desktop_app_memory_supervisor_history(
        self,
        *,
        status: str = "",
        source: str = "",
        history_response_limit: int = 6,
    ) -> Dict[str, Any]:
        del status, source
        removed_count = len(self.desktop_app_memory_daemon_runs)
        self.desktop_app_memory_daemon_runs = []
        return {
            "status": "success",
            "removed_count": removed_count,
            "remaining_count": 0,
            "latest_run": {},
            "supervisor": self.desktop_app_memory_supervisor_status(history_limit=history_response_limit),
        }

