    def desktop_evaluation_create_lab_session(
        self,
        *,
        scenario_name: str = "",
        pack: str = "",
        category: str = "",
        capability: str = "",
        risk_level: str = "",
        autonomy_tier: str = "",
        mission_family: str = "",
        app_name: str = "",
        limit: int = 200,
        history_limit: int = 8,
        source: str = "",
        label: str = "",
    ) -> Dict[str, Any]:
        lab = self.desktop_evaluation_lab(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        session_id = f"benchlab-test-{len(self.desktop_evaluation_lab_sessions_items) + 1}"
        created_at = datetime.now(timezone.utc).isoformat()
        replay_candidates = [
            {
                **dict(item),
                "replay_status": "pending",
                "replay_count": 0,
            }
            for item in lab.get("replay_candidates", [])[:6]
            if isinstance(item, dict)
        ]
        long_horizon_candidate_count = sum(
            1 for item in replay_candidates if int(item.get("horizon_steps", 1) or 1) >= 4
        )
        latest_score = float(dict(lab.get("latest_summary", {})).get("weighted_score", 0.0) or 0.0)
        latest_pass_rate = float(dict(lab.get("latest_summary", {})).get("weighted_pass_rate", 0.0) or 0.0)
        session = {
            "session_id": session_id,
            "status": "ready",
            "label": str(label or pack or category or app_name or "benchmark lab session"),
            "source": str(source or "action_control_panel"),
            "created_at": created_at,
            "updated_at": created_at,
            "focus_summary": list(native_targets.get("focus_summary", [])),
            "replay_candidates": replay_candidates,
            "replay_candidate_count": len(replay_candidates),
            "pending_replay_count": len(replay_candidates),
            "failed_replay_count": 0,
            "completed_replay_count": 0,
            "long_horizon_candidate_count": long_horizon_candidate_count,
            "long_horizon_pending_count": long_horizon_candidate_count,
            "run_cycles": [
                {
                    "cycle_id": f"{session_id}-cycle-1",
                    "kind": "seed",
                    "recorded_at": created_at,
                    "executed_at": str(dict(lab.get("latest_run", {})).get("executed_at", created_at) or created_at),
                    "status": "success",
                    "regression_status": str(dict(lab.get("latest_regression", {})).get("status", "baseline") or "baseline"),
                    "weighted_score": latest_score,
                    "weighted_pass_rate": latest_pass_rate,
                    "scenario_count": int(dict(lab.get("catalog_summary", {})).get("scenario_count", 0) or 0),
                    "history_direction": str(dict(lab.get("history_trend", {})).get("direction", "") or ""),
                    "replay_candidate_count": len(replay_candidates),
                    "long_horizon_count": int(dict(dict(lab.get("coverage", {})).get("long_horizon", {})).get("count", 0) or 0),
                    "target_app_count": len(native_targets.get("target_apps", [])),
                    "query": dict(lab.get("filters", {})),
                }
            ],
            "cycle_count": 1,
            "completed_cycle_count": 1,
            "regression_cycle_count": 0,
            "latest_cycle_status": "success",
            "latest_cycle_regression_status": str(dict(lab.get("latest_regression", {})).get("status", "baseline") or "baseline"),
            "latest_cycle_score": latest_score,
            "latest_cycle_pass_rate": latest_pass_rate,
            "latest_cycle_executed_at": str(dict(lab.get("latest_run", {})).get("executed_at", created_at) or created_at),
            "target_app_count": len(native_targets.get("target_apps", [])),
            "target_apps": [str(item.get("app_name", "") or "") for item in native_targets.get("target_apps", []) if isinstance(item, dict)],
            "strongest_tactics": dict(native_targets.get("strongest_tactics", {})),
            "coverage_gap_apps": list(native_targets.get("coverage_gap_apps", [])),
            "history_direction": str(dict(lab.get("history_trend", {})).get("direction", "") or ""),
            "latest_weighted_score": latest_score,
            "latest_weighted_pass_rate": latest_pass_rate,
            "filters": dict(lab.get("filters", {})),
            "catalog_summary": dict(lab.get("catalog_summary", {})),
            "coverage": dict(lab.get("coverage", {})),
            "history_trend": dict(lab.get("history_trend", {})),
            "lab_snapshot": dict(lab),
            "native_targets_snapshot": dict(native_targets),
            "guidance_snapshot": dict(guidance),
        }
        self.desktop_evaluation_lab_sessions_items.insert(0, session)
        self.desktop_evaluation_lab_sessions_items = self.desktop_evaluation_lab_sessions_items[:12]
        return {
            "status": "success",
            "session": dict(session),
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_create_lab_campaign(
        self,
        *,
        scenario_name: str = "",
        pack: str = "",
        category: str = "",
        capability: str = "",
        risk_level: str = "",
        autonomy_tier: str = "",
        mission_family: str = "",
        app_name: str = "",
        limit: int = 200,
        history_limit: int = 8,
        source: str = "",
        label: str = "",
        max_sessions: int = 4,
    ) -> Dict[str, Any]:
        lab = self.desktop_evaluation_lab(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        target_apps = []
        if str(app_name or "").strip():
            target_apps.append(str(app_name).strip())
        for item in native_targets.get("target_apps", []):
            if not isinstance(item, dict):
                continue
            name = str(item.get("app_name", "") or "").strip()
            if name and name not in target_apps:
                target_apps.append(name)
        target_apps = target_apps[: max(1, int(max_sessions or 4))]
        created_sessions: list[Dict[str, Any]] = []
        session_ids: list[str] = []
        if not target_apps:
            target_apps = [str(app_name or "").strip() or "settings"]
        for target_app in target_apps:
            session_payload = self.desktop_evaluation_create_lab_session(
                scenario_name=scenario_name,
                pack=pack,
                category=category,
                capability=capability,
                risk_level=risk_level,
                autonomy_tier=autonomy_tier,
                mission_family=mission_family,
                app_name=target_app,
                limit=limit,
                history_limit=history_limit,
                source=source or "benchmark_campaign",
                label=f"{str(label or 'replay campaign').strip()} / {target_app}",
            )
            if str(session_payload.get("status", "") or "").strip().lower() != "success":
                continue
            created_sessions.append(dict(session_payload.get("session", {})))
            session_id = str(dict(session_payload.get("session", {})).get("session_id", "") or "").strip()
            if session_id:
                session_ids.append(session_id)
        campaign_id = f"benchcampaign-test-{len(self.desktop_evaluation_lab_campaigns_items) + 1}"
        created_at = datetime.now(timezone.utc).isoformat()
        campaign = self._desktop_evaluation_refresh_campaign_row(
            {
                "campaign_id": campaign_id,
                "status": "ready",
                "label": str(label or pack or app_name or "benchmark replay campaign"),
                "source": str(source or "action_control_panel"),
                "created_at": created_at,
                "updated_at": created_at,
                "filters": dict(lab.get("filters", {})),
                "focus_summary": list(native_targets.get("focus_summary", [])),
                "session_ids": session_ids,
                "target_apps": target_apps,
                "lab_snapshot": dict(lab),
                "native_targets_snapshot": dict(native_targets),
                "guidance_snapshot": dict(guidance),
                "sweep_runs": [],
            }
        )
        self.desktop_evaluation_lab_campaigns_items.insert(0, campaign)
        self.desktop_evaluation_lab_campaigns_items = self.desktop_evaluation_lab_campaigns_items[:8]
        return {
            "status": "success",
            "campaign": dict(campaign),
            "created_sessions": created_sessions,
            "created_session_count": len(created_sessions),
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_replay_lab_session(
        self,
        *,
        session_id: str = "",
        scenario_name: str = "",
    ) -> Dict[str, Any]:
        selected = next(
            (
                item
                for item in self.desktop_evaluation_lab_sessions_items
                if str(item.get("session_id", "") or "").strip() == str(session_id or "").strip()
            ),
            None,
        )
        if not isinstance(selected, dict):
            return {"status": "error", "message": "benchmark lab session not found"}
        candidates = [
            dict(item)
            for item in selected.get("replay_candidates", [])
            if isinstance(item, dict)
        ]
        chosen = next(
            (
                item
                for item in candidates
                if str(item.get("scenario", "") or "").strip() == str(scenario_name or "").strip()
            ),
            candidates[0] if candidates else None,
        )
        if not isinstance(chosen, dict):
            return {"status": "error", "message": "benchmark lab session has no replay candidates"}
        replay_query = dict(chosen.get("replay_query", {})) if isinstance(chosen.get("replay_query", {}), dict) else {}
        replay_result = self.desktop_evaluation_run(
            scenario_name=str(replay_query.get("scenario_name", chosen.get("scenario", "")) or ""),
            pack=str(replay_query.get("pack", "") or ""),
            category=str(replay_query.get("category", "") or ""),
            capability=str(replay_query.get("capability", "") or ""),
            risk_level=str(replay_query.get("risk_level", "") or ""),
            autonomy_tier=str(replay_query.get("autonomy_tier", "") or ""),
            mission_family=str(replay_query.get("mission_family", "") or ""),
            app_name=str(replay_query.get("app", replay_query.get("app_name", "")) or ""),
            limit=int(replay_query.get("limit", 1) or 1),
        )
        updated_candidates: list[Dict[str, Any]] = []
        for item in candidates:
            updated = dict(item)
            if str(updated.get("scenario", "") or "").strip() == str(chosen.get("scenario", "") or "").strip():
                updated["replay_status"] = "completed"
                updated["replay_count"] = int(updated.get("replay_count", 0) or 0) + 1
                updated["last_replayed_at"] = datetime.now(timezone.utc).isoformat()
            updated_candidates.append(updated)
        selected["replay_candidates"] = updated_candidates
        selected["pending_replay_count"] = sum(
            1
            for item in updated_candidates
            if str(item.get("replay_status", "pending") or "pending").strip().lower() == "pending"
        )
        selected["completed_replay_count"] = sum(
            1
            for item in updated_candidates
            if str(item.get("replay_status", "") or "").strip().lower() == "completed"
        )
        selected["failed_replay_count"] = 0
        selected["updated_at"] = datetime.now(timezone.utc).isoformat()
        selected["latest_weighted_score"] = float(dict(replay_result.get("summary", {})).get("weighted_score", 0.0) or 0.0)
        selected["latest_weighted_pass_rate"] = float(dict(replay_result.get("summary", {})).get("weighted_pass_rate", 0.0) or 0.0)
        selected["long_horizon_pending_count"] = sum(
            1
            for item in updated_candidates
            if int(item.get("horizon_steps", 1) or 1) >= 4
            and str(item.get("replay_status", "pending") or "pending").strip().lower() == "pending"
        )
        selected["status"] = "complete" if int(selected.get("pending_replay_count", 0) or 0) == 0 else "ready"
        refreshed_lab = self.desktop_evaluation_lab(
            pack=str(dict(selected.get("filters", {})).get("pack", "") or ""),
            category=str(dict(selected.get("filters", {})).get("category", "") or ""),
            capability=str(dict(selected.get("filters", {})).get("capability", "") or ""),
            risk_level=str(dict(selected.get("filters", {})).get("risk_level", "") or ""),
            autonomy_tier=str(dict(selected.get("filters", {})).get("autonomy_tier", "") or ""),
            mission_family=str(dict(selected.get("filters", {})).get("mission_family", "") or ""),
            app_name=str(dict(selected.get("filters", {})).get("app", "") or ""),
            limit=int(dict(selected.get("filters", {})).get("limit", 200) or 200),
            history_limit=8,
        )
        native_targets = self.desktop_evaluation_native_targets()
        guidance = self.desktop_evaluation_guidance()
        selected["lab_snapshot"] = dict(refreshed_lab)
        selected["native_targets_snapshot"] = dict(native_targets)
        selected["guidance_snapshot"] = dict(guidance)
        return {
            "status": "success",
            "session": dict(selected),
            "replay_candidate": dict(chosen),
            "updated_candidate": next(
                (
                    dict(item)
                    for item in updated_candidates
                    if str(item.get("scenario", "") or "").strip() == str(chosen.get("scenario", "") or "").strip()
                ),
                {},
            ),
            "replay_result": dict(replay_result),
            "lab": dict(refreshed_lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_run_lab_session_cycle(
        self,
        *,
        session_id: str = "",
        history_limit: int = 8,
    ) -> Dict[str, Any]:
        selected = next(
            (
                item
                for item in self.desktop_evaluation_lab_sessions_items
                if str(item.get("session_id", "") or "").strip() == str(session_id or "").strip()
            ),
            None,
        )
        if not isinstance(selected, dict):
            return {"status": "error", "message": "benchmark lab session not found"}
        filters = dict(selected.get("filters", {}))
        cycle_result = self.desktop_evaluation_run(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
        )
        refreshed_lab = self.desktop_evaluation_lab(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        cycle_recorded_at = datetime.now(timezone.utc).isoformat()
        cycle = {
            "cycle_id": f"{selected['session_id']}-cycle-{int(selected.get('cycle_count', 0) or 0) + 1}",
            "kind": "run_cycle",
            "recorded_at": cycle_recorded_at,
            "executed_at": str(cycle_result.get("executed_at", "") or cycle_recorded_at),
            "status": str(cycle_result.get("status", "") or "success"),
            "regression_status": str(dict(cycle_result.get("regression", {})).get("status", "stable") or "stable"),
            "weighted_score": float(dict(cycle_result.get("summary", {})).get("weighted_score", 0.0) or 0.0),
            "weighted_pass_rate": float(dict(cycle_result.get("summary", {})).get("weighted_pass_rate", 0.0) or 0.0),
            "scenario_count": int(cycle_result.get("scenario_count", len(cycle_result.get("items", []))) or 0),
            "history_direction": str(dict(refreshed_lab.get("history_trend", {})).get("direction", "") or ""),
            "replay_candidate_count": len(refreshed_lab.get("replay_candidates", [])),
            "long_horizon_count": int(dict(dict(refreshed_lab.get("coverage", {})).get("long_horizon", {})).get("count", 0) or 0),
            "target_app_count": len(native_targets.get("target_apps", [])),
            "query": {
                **filters,
                "history_limit": history_limit,
            },
        }
        run_cycles = [
            dict(item)
            for item in selected.get("run_cycles", [])
            if isinstance(item, dict)
        ]
        run_cycles.append(cycle)
        selected["run_cycles"] = run_cycles[-24:]
        selected["cycle_count"] = len(selected["run_cycles"])
        selected["completed_cycle_count"] = sum(
            1 for item in selected["run_cycles"] if str(item.get("status", "") or "").strip().lower() in {"success", "completed"}
        )
        selected["regression_cycle_count"] = sum(
            1 for item in selected["run_cycles"] if str(item.get("regression_status", "") or "").strip().lower() == "regression"
        )
        selected["latest_cycle_status"] = str(cycle["status"] or "")
        selected["latest_cycle_regression_status"] = str(cycle["regression_status"] or "")
        selected["latest_cycle_score"] = float(cycle["weighted_score"] or 0.0)
        selected["latest_cycle_pass_rate"] = float(cycle["weighted_pass_rate"] or 0.0)
        selected["latest_cycle_executed_at"] = str(cycle["executed_at"] or "")
        selected["latest_weighted_score"] = float(cycle["weighted_score"] or 0.0)
        selected["latest_weighted_pass_rate"] = float(cycle["weighted_pass_rate"] or 0.0)
        selected["updated_at"] = cycle_recorded_at
        selected["status"] = (
            "attention"
            if str(cycle["regression_status"] or "").strip().lower() == "regression"
            else ("complete" if int(selected.get("pending_replay_count", 0) or 0) == 0 else "ready")
        )
        selected["lab_snapshot"] = dict(refreshed_lab)
        selected["native_targets_snapshot"] = dict(native_targets)
        selected["guidance_snapshot"] = dict(guidance)
        return {
            "status": "success",
            "session": dict(selected),
            "cycle": dict(cycle),
            "cycle_result": dict(cycle_result),
            "lab": dict(refreshed_lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_advance_lab_session(
        self,
        *,
        session_id: str = "",
        max_replays: int = 2,
        replay_status: str = "",
    ) -> Dict[str, Any]:
        selected = next(
            (
                item
                for item in self.desktop_evaluation_lab_sessions_items
                if str(item.get("session_id", "") or "").strip() == str(session_id or "").strip()
            ),
            None,
        )
        if not isinstance(selected, dict):
            return {"status": "error", "message": "benchmark lab session not found"}
        candidates = [
            dict(item)
            for item in selected.get("replay_candidates", [])
            if isinstance(item, dict)
        ]
        clean_replay_status = str(replay_status or "").strip().lower()
        chosen: list[Dict[str, Any]] = []
        for candidate in candidates:
            candidate_status = str(candidate.get("replay_status", "pending") or "pending").strip().lower()
            if clean_replay_status == "failed" and candidate_status != "failed":
                continue
            if clean_replay_status == "pending" and candidate_status not in {"pending", "ready", "queued", "staged"}:
                continue
            if not clean_replay_status and candidate_status == "completed":
                continue
            chosen.append(candidate)
            if len(chosen) >= max(1, int(max_replays or 2)):
                break
        if not chosen:
            return {"status": "error", "message": "benchmark lab session has no replay candidates for the requested batch"}
        results: list[Dict[str, Any]] = []
        final_payload: Dict[str, Any] = {"status": "success", "session": dict(selected)}
        replayed_scenarios: list[str] = []
        for candidate in chosen:
            payload = self.desktop_evaluation_replay_lab_session(
                session_id=session_id,
                scenario_name=str(candidate.get("scenario", "") or ""),
            )
            results.append(
                {
                    "scenario": str(candidate.get("scenario", "") or ""),
                    "status": str(payload.get("status", "") or "success"),
                    "updated_candidate": dict(payload.get("updated_candidate", {})),
                }
            )
            if payload.get("status") == "success":
                replayed_scenarios.append(str(candidate.get("scenario", "") or ""))
                final_payload = payload
        return {
            "status": "success",
            "session": dict(final_payload.get("session", {})),
            "results": results,
            "batch_count": len(results),
            "replayed_scenarios": replayed_scenarios,
            "lab": dict(final_payload.get("lab", {})),
            "native_targets": dict(final_payload.get("native_targets", {})),
            "guidance": dict(final_payload.get("guidance", {})),
        }

    def desktop_evaluation_run_lab_campaign_sweep(
        self,
        *,
        campaign_id: str = "",
        max_sessions: int = 3,
        max_replays_per_session: int = 2,
        history_limit: int = 8,
    ) -> Dict[str, Any]:
        selected = next(
            (
                item
                for item in self.desktop_evaluation_lab_campaigns_items
                if str(item.get("campaign_id", "") or "").strip() == str(campaign_id or "").strip()
            ),
            None,
        )
        if not isinstance(selected, dict):
            return {"status": "error", "message": "benchmark lab campaign not found"}
        session_ids = [
            str(item).strip()
            for item in selected.get("session_ids", [])
            if str(item).strip()
        ] if isinstance(selected.get("session_ids", []), list) else []
        sessions = [
            dict(item)
            for item in self.desktop_evaluation_lab_sessions_items
            if str(item.get("session_id", "") or "").strip() in session_ids
        ]
        ranked = sorted(
            sessions,
            key=lambda item: (
                1 if str(item.get("status", "") or "").strip().lower() == "attention" else 0,
                int(item.get("failed_replay_count", 0) or 0),
                int(item.get("pending_replay_count", 0) or 0),
                int(item.get("long_horizon_pending_count", 0) or 0),
            ),
            reverse=True,
        )[: max(1, int(max_sessions or 3))]
        results: list[Dict[str, Any]] = []
        for session in ranked:
            session_id = str(session.get("session_id", "") or "").strip()
            cycle_payload = self.desktop_evaluation_run_lab_session_cycle(
                session_id=session_id,
                history_limit=history_limit,
            )
            advance_payload = self.desktop_evaluation_advance_lab_session(
                session_id=session_id,
                max_replays=max_replays_per_session,
            )
            latest_session = (
                dict(advance_payload.get("session", {}))
                if isinstance(advance_payload.get("session", {}), dict)
                else dict(cycle_payload.get("session", {}))
            )
            results.append(
                {
                    "session_id": session_id,
                    "label": str(latest_session.get("label", "") or ""),
                    "status": str(advance_payload.get("status", cycle_payload.get("status", "success")) or "success"),
                    "pending_replay_count": int(latest_session.get("pending_replay_count", 0) or 0),
                    "regression_cycle_count": int(latest_session.get("regression_cycle_count", 0) or 0),
                }
            )
        selected.setdefault("sweep_runs", [])
        selected["sweep_runs"].append(
            {
                "sweep_id": f"{selected['campaign_id']}-sweep-{len(selected['sweep_runs']) + 1}",
                "executed_at": datetime.now(timezone.utc).isoformat(),
                "status": "success",
                "regression_status": "regression"
                if any(int(item.get("regression_cycle_count", 0) or 0) > 0 for item in results)
                else "stable",
                "executed_session_count": len(results),
                "created_session_count": 0,
                "pending_session_count": sum(
                    1
                    for item in self.desktop_evaluation_lab_sessions_items
                    if str(item.get("session_id", "") or "").strip() in session_ids
                    and str(item.get("status", "") or "").strip().lower() != "complete"
                ),
                "attention_session_count": sum(
                    1
                    for item in self.desktop_evaluation_lab_sessions_items
                    if str(item.get("session_id", "") or "").strip() in session_ids
                    and str(item.get("status", "") or "").strip().lower() == "attention"
                ),
                "long_horizon_pending_count": sum(
                    int(item.get("long_horizon_pending_count", 0) or 0)
                    for item in self.desktop_evaluation_lab_sessions_items
                    if str(item.get("session_id", "") or "").strip() in session_ids
                ),
                "pending_app_target_count": 0,
                "query": {"history_limit": history_limit, "max_sessions": max_sessions},
            }
        )
        selected = self._desktop_evaluation_refresh_campaign_row(selected)
        for index, item in enumerate(self.desktop_evaluation_lab_campaigns_items):
            if str(item.get("campaign_id", "") or "").strip() == str(selected.get("campaign_id", "") or "").strip():
                self.desktop_evaluation_lab_campaigns_items[index] = selected
                break
        filters = dict(selected.get("filters", {}))
        lab = self.desktop_evaluation_lab(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        return {
            "status": "success",
            "campaign": dict(selected),
            "sweep": dict(selected.get("sweep_runs", [])[-1]) if selected.get("sweep_runs") else {},
            "results": results,
            "created_sessions": [],
            "created_session_count": 0,
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_run_lab_campaign_cycle(
        self,
        *,
        campaign_id: str = "",
        max_sweeps: int = 2,
        max_sessions: int = 3,
        max_replays_per_session: int = 2,
        history_limit: int = 8,
        stop_on_stable: bool = True,
    ) -> Dict[str, Any]:
        normalized_max_sweeps = max(1, int(max_sweeps or 2))
        results: list[Dict[str, Any]] = []
        final_payload: Dict[str, Any] = {}
        stop_reason = "max_sweeps_reached"
        for _ in range(normalized_max_sweeps):
            sweep = self.desktop_evaluation_run_lab_campaign_sweep(
                campaign_id=campaign_id,
                max_sessions=max_sessions,
                max_replays_per_session=max_replays_per_session,
                history_limit=history_limit,
            )
            final_payload = dict(sweep)
            campaign = dict(sweep.get("campaign", {})) if isinstance(sweep.get("campaign", {}), dict) else {}
            results.append(
                {
                    "campaign_id": str(campaign.get("campaign_id", campaign_id) or campaign_id),
                    "status": str(sweep.get("status", "") or "success"),
                    "pending_session_count": int(campaign.get("pending_session_count", 0) or 0),
                    "attention_session_count": int(campaign.get("attention_session_count", 0) or 0),
                    "pending_app_target_count": int(campaign.get("pending_app_target_count", 0) or 0),
                }
            )
            if (
                stop_on_stable
                and int(campaign.get("pending_session_count", 0) or 0) <= 0
                and int(campaign.get("attention_session_count", 0) or 0) <= 0
                and int(campaign.get("pending_app_target_count", 0) or 0) <= 0
            ):
                stop_reason = "stable"
                break
        return {
            "status": str(final_payload.get("status", "") or "success"),
            "message": f"campaign cycle executed {len(results)} sweep(s) | stop:{stop_reason}",
            "campaign": dict(final_payload.get("campaign", {})) if isinstance(final_payload.get("campaign", {}), dict) else {},
            "cycle": {
                "executed_sweep_count": len(results),
                "stop_reason": stop_reason,
                "stable": stop_reason == "stable",
            },
            "results": results,
            "lab": dict(final_payload.get("lab", {})) if isinstance(final_payload.get("lab", {}), dict) else {},
            "native_targets": dict(final_payload.get("native_targets", {})) if isinstance(final_payload.get("native_targets", {}), dict) else {},
            "guidance": dict(final_payload.get("guidance", {})) if isinstance(final_payload.get("guidance", {}), dict) else {},
        }

    def desktop_evaluation_create_lab_program(
        self,
        *,
        scenario_name: str = "",
        pack: str = "",
        category: str = "",
        capability: str = "",
        risk_level: str = "",
        autonomy_tier: str = "",
        mission_family: str = "",
        app_name: str = "",
        limit: int = 200,
        history_limit: int = 8,
        source: str = "",
        label: str = "",
        max_campaigns: int = 3,
        max_sessions_per_campaign: int = 3,
    ) -> Dict[str, Any]:
        lab = self.desktop_evaluation_lab(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        normalized_max_campaigns = max(1, int(max_campaigns or 3))
        normalized_max_sessions = max(1, int(max_sessions_per_campaign or 3))
        target_apps: list[str] = []
        if str(app_name or "").strip():
            target_apps.append(str(app_name).strip())
        for item in native_targets.get("target_apps", []):
            if not isinstance(item, dict):
                continue
            name = str(item.get("app_name", "") or "").strip()
            if name and name.lower() not in {value.lower() for value in target_apps}:
                target_apps.append(name)
        target_apps = target_apps[:normalized_max_campaigns]
        if not target_apps:
            target_apps = ["settings"]
        created_campaigns: list[Dict[str, Any]] = []
        campaign_ids: list[str] = []
        base_label = str(label or pack or category or app_name or "benchmark replay program")
        for target_app in target_apps[:normalized_max_campaigns]:
            campaign_label = (
                f"{base_label} / {target_app}"
                if base_label and len(target_apps) > 1
                else (base_label or f"{target_app} replay program")
            )
            payload = self.desktop_evaluation_create_lab_campaign(
                scenario_name=scenario_name,
                pack=pack,
                category=category,
                capability=capability,
                risk_level=risk_level,
                autonomy_tier=autonomy_tier,
                mission_family=mission_family,
                app_name=target_app,
                limit=limit,
                history_limit=history_limit,
                source=source or "benchmark_program",
                label=campaign_label,
                max_sessions=normalized_max_sessions,
            )
            if str(payload.get("status", "") or "").strip().lower() != "success":
                continue
            created_campaigns.append(dict(payload))
            campaign = dict(payload.get("campaign", {})) if isinstance(payload.get("campaign", {}), dict) else {}
            campaign_id = str(campaign.get("campaign_id", "") or "").strip()
            if campaign_id:
                campaign_ids.append(campaign_id)
        program_id = f"benchprogram-test-{len(self.desktop_evaluation_lab_programs_items) + 1}"
        created_at = datetime.now(timezone.utc).isoformat()
        program = {
            "program_id": program_id,
            "status": "ready",
            "label": base_label,
            "source": str(source or "action_control_panel"),
            "created_at": created_at,
            "updated_at": created_at,
            "filters": dict(lab.get("filters", {})),
            "focus_summary": list(native_targets.get("focus_summary", [])),
            "campaign_ids": list(campaign_ids),
            "target_apps": list(target_apps),
            "app_targets": list(target_apps),
            "target_app_count": len(target_apps),
            "cycle_runs": [],
            "cycle_count": 0,
            "completed_cycle_count": 0,
            "stable_cycle_count": 0,
            "regression_cycle_count": 0,
            "stable_cycle_streak": 0,
            "regression_cycle_streak": 0,
            "latest_cycle_status": "",
            "latest_cycle_stop_reason": "",
            "latest_cycle_executed_at": "",
            "latest_cycle_executed_campaign_count": 0,
            "latest_cycle_executed_sweep_count": 0,
            "latest_cycle_weighted_score": 0.0,
            "latest_cycle_weighted_pass_rate": 0.0,
            "latest_cycle_trend_direction": "",
            "history_direction": "",
            "trend_summary": {},
            "lab_snapshot": dict(lab),
            "native_targets_snapshot": dict(native_targets),
            "guidance_snapshot": dict(guidance),
        }
        program = self._desktop_evaluation_refresh_program_row(program)
        self.desktop_evaluation_lab_programs_items.insert(0, program)
        self.desktop_evaluation_lab_programs_items = self.desktop_evaluation_lab_programs_items[:8]
        created_session_count = sum(
            int(item.get("created_session_count", 0) or 0)
            for item in created_campaigns
            if isinstance(item, dict)
        )
        return {
            "status": "success",
            "program": dict(program),
            "created_campaigns": created_campaigns,
            "created_campaign_count": len(created_campaigns),
            "created_session_count": created_session_count,
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_run_lab_program_cycle(
        self,
        *,
        program_id: str = "",
        max_campaigns: int = 3,
        max_sweeps_per_campaign: int = 2,
        max_sessions: int = 3,
        max_replays_per_session: int = 2,
        history_limit: int = 8,
        stop_on_stable: bool = True,
    ) -> Dict[str, Any]:
        normalized_max_campaigns = max(1, int(max_campaigns or 3))
        selected: Dict[str, Any] | None = None
        selected_index = -1
        for index, item in enumerate(self.desktop_evaluation_lab_programs_items):
            if str(item.get("program_id", "") or "").strip() == str(program_id or "").strip():
                selected = self._desktop_evaluation_refresh_program_row(dict(item))
                selected_index = index
                break
        if selected is None:
            return {"status": "error", "message": "benchmark lab program not found"}
        filters = dict(selected.get("filters", {})) if isinstance(selected.get("filters", {}), dict) else {}
        program_campaign_ids = [
            str(item).strip()
            for item in selected.get("campaign_ids", [])
            if str(item).strip()
        ] if isinstance(selected.get("campaign_ids", []), list) else []
        current_campaigns = [
            self._desktop_evaluation_refresh_campaign_row(dict(item))
            for item in self.desktop_evaluation_lab_campaigns_items
            if str(item.get("campaign_id", "") or "").strip() in program_campaign_ids
        ]
        represented_apps = {
            str(item.get("filters", {}).get("app", item.get("filters", {}).get("app_name", "")) or "")
            .strip()
            .lower()
            for item in current_campaigns
            if isinstance(item.get("filters", {}), dict)
            and str(item.get("filters", {}).get("app", item.get("filters", {}).get("app_name", "")) or "").strip()
        }
        app_targets = [
            str(item).strip()
            for item in selected.get("target_apps", selected.get("app_targets", []))
            if str(item).strip()
        ] if isinstance(selected.get("target_apps", selected.get("app_targets", [])), list) else []
        created_campaigns: list[Dict[str, Any]] = []
        for target_app in app_targets:
            if target_app.strip().lower() in represented_apps:
                continue
            if len(current_campaigns) + len(created_campaigns) >= max(normalized_max_campaigns, len(current_campaigns)):
                break
            payload = self.desktop_evaluation_create_lab_campaign(
                scenario_name=str(filters.get("scenario_name", "") or ""),
                pack=str(filters.get("pack", "") or ""),
                category=str(filters.get("category", "") or ""),
                capability=str(filters.get("capability", "") or ""),
                risk_level=str(filters.get("risk_level", "") or ""),
                autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
                mission_family=str(filters.get("mission_family", "") or ""),
                app_name=target_app,
                limit=int(filters.get("limit", 200) or 200),
                history_limit=history_limit,
                source="benchmark_program_cycle",
                label=f"{str(selected.get('label', '') or 'replay program').strip()} / {target_app}",
                max_sessions=max(1, int(max_sessions or 3)),
            )
            if str(payload.get("status", "") or "").strip().lower() != "success":
                continue
            created_campaigns.append(dict(payload))
            campaign = dict(payload.get("campaign", {})) if isinstance(payload.get("campaign", {}), dict) else {}
            campaign_id = str(campaign.get("campaign_id", "") or "").strip()
            if campaign_id and campaign_id not in program_campaign_ids:
                program_campaign_ids.append(campaign_id)
                current_campaigns.append(self._desktop_evaluation_refresh_campaign_row(campaign))
        ranked_campaigns = sorted(
            current_campaigns,
            key=lambda item: (
                1 if str(item.get("status", "") or "").strip().lower() == "attention" else 0,
                int(item.get("attention_session_count", 0) or 0),
                int(item.get("pending_session_count", 0) or 0),
                int(item.get("pending_app_target_count", 0) or 0),
                int(item.get("long_horizon_pending_count", 0) or 0),
            ),
            reverse=True,
        )[:normalized_max_campaigns]
        results: list[Dict[str, Any]] = []
        for campaign in ranked_campaigns:
            campaign_id = str(campaign.get("campaign_id", "") or "").strip()
            if not campaign_id:
                continue
            results.append(
                self.desktop_evaluation_run_lab_campaign_cycle(
                    campaign_id=campaign_id,
                    max_sweeps=max_sweeps_per_campaign,
                    max_sessions=max_sessions,
                    max_replays_per_session=max_replays_per_session,
                    history_limit=history_limit,
                    stop_on_stable=stop_on_stable,
                )
            )
        refreshed_campaigns = [
            self._desktop_evaluation_refresh_campaign_row(dict(item))
            for item in self.desktop_evaluation_lab_campaigns_items
            if str(item.get("campaign_id", "") or "").strip() in program_campaign_ids
        ]
        selected["campaign_ids"] = list(program_campaign_ids)
        selected["target_apps"] = list(
            dict.fromkeys(
                [
                    *app_targets,
                    *[
                        str(item.get("filters", {}).get("app", item.get("filters", {}).get("app_name", "")) or "")
                        .strip()
                        for item in refreshed_campaigns
                        if isinstance(item.get("filters", {}), dict)
                        and str(item.get("filters", {}).get("app", item.get("filters", {}).get("app_name", "")) or "").strip()
                    ],
                ]
            )
        )
        lab = self.desktop_evaluation_lab(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        stable = bool(results) and all(bool(dict(item.get("cycle", {})).get("stable", False)) for item in results)
        trend_direction = (
            "regression"
            if any(
                str(dict(item.get("campaign", {})).get("latest_sweep_regression_status", "") or "").strip().lower()
                in {"regression", "failed", "error"}
                for item in results
            )
            else str(dict(lab.get("history_trend", {})).get("direction", "") or "").strip().lower()
        )
        cycle_row = {
            "cycle_id": f"{str(selected.get('program_id', '') or program_id).strip()}-cycle-{int(selected.get('cycle_count', 0) or 0) + 1}",
            "recorded_at": datetime.now(timezone.utc).isoformat(),
            "executed_at": datetime.now(timezone.utc).isoformat(),
            "status": "success" if results else "idle",
            "stop_reason": "stable" if stable and stop_on_stable else ("idle" if not results else "campaign_budget_reached"),
            "stable": stable,
            "executed_campaign_count": len(results),
            "executed_sweep_count": sum(
                int(dict(item.get("cycle", {})).get("executed_sweep_count", 0) or 0)
                for item in results
            ),
            "created_campaign_count": len(created_campaigns),
            "created_session_count": sum(
                int(item.get("created_session_count", 0) or 0)
                for item in created_campaigns
                if isinstance(item, dict)
            ),
            "weighted_score": round(
                float(dict(lab.get("latest_summary", {})).get("weighted_score", 0.0) or 0.0),
                6,
            ),
            "weighted_pass_rate": round(
                float(dict(lab.get("latest_summary", {})).get("weighted_pass_rate", 0.0) or 0.0),
                6,
            ),
            "trend_direction": trend_direction,
            "program_priority": "critical" if trend_direction == "regression" else "elevated",
        }
        selected.setdefault("cycle_runs", [])
        if not isinstance(selected.get("cycle_runs", []), list):
            selected["cycle_runs"] = []
        selected["cycle_runs"].append(cycle_row)
        selected["lab_snapshot"] = dict(lab)
        selected["native_targets_snapshot"] = dict(native_targets)
        selected["guidance_snapshot"] = dict(guidance)
        selected = self._desktop_evaluation_refresh_program_row(selected)
        if 0 <= selected_index < len(self.desktop_evaluation_lab_programs_items):
            self.desktop_evaluation_lab_programs_items[selected_index] = selected
        return {
            "status": "success",
            "program": dict(selected),
            "cycle": dict(cycle_row),
            "results": results,
            "created_campaigns": created_campaigns,
            "created_campaign_count": len(created_campaigns),
            "created_session_count": sum(
                int(item.get("created_session_count", 0) or 0)
                for item in created_campaigns
                if isinstance(item, dict)
            ),
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_create_lab_portfolio(
        self,
        *,
        scenario_name: str = "",
        pack: str = "",
        category: str = "",
        capability: str = "",
        risk_level: str = "",
        autonomy_tier: str = "",
        mission_family: str = "",
        app_name: str = "",
        limit: int = 200,
        history_limit: int = 8,
        source: str = "",
        label: str = "",
        max_programs: int = 3,
        max_campaigns_per_program: int = 3,
        max_sessions_per_campaign: int = 3,
    ) -> Dict[str, Any]:
        lab = self.desktop_evaluation_lab(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=scenario_name,
            pack=pack,
            category=category,
            capability=capability,
            risk_level=risk_level,
            autonomy_tier=autonomy_tier,
            mission_family=mission_family,
            app_name=app_name,
            limit=limit,
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        normalized_max_programs = max(1, int(max_programs or 3))
        normalized_max_campaigns = max(1, int(max_campaigns_per_program or 3))
        normalized_max_sessions = max(1, int(max_sessions_per_campaign or 3))
        target_apps: list[str] = []
        if str(app_name or "").strip():
            target_apps.append(str(app_name).strip())
        for item in native_targets.get("target_apps", []):
            if not isinstance(item, dict):
                continue
            name = str(item.get("app_name", "") or "").strip()
            if name and name.lower() not in {value.lower() for value in target_apps}:
                target_apps.append(name)
        target_apps = target_apps[:normalized_max_programs]
        if not target_apps:
            target_apps = ["settings"]
        created_programs: list[Dict[str, Any]] = []
        program_ids: list[str] = []
        base_label = str(label or pack or category or app_name or "benchmark replay portfolio")
        for target_app in target_apps[:normalized_max_programs]:
            program_label = (
                f"{base_label} / {target_app}"
                if base_label and len(target_apps) > 1
                else (base_label or f"{target_app} replay portfolio")
            )
            payload = self.desktop_evaluation_create_lab_program(
                scenario_name=scenario_name,
                pack=pack,
                category=category,
                capability=capability,
                risk_level=risk_level,
                autonomy_tier=autonomy_tier,
                mission_family=mission_family,
                app_name=target_app,
                limit=limit,
                history_limit=history_limit,
                source=source or "benchmark_portfolio",
                label=program_label,
                max_campaigns=normalized_max_campaigns,
                max_sessions_per_campaign=normalized_max_sessions,
            )
            if str(payload.get("status", "") or "").strip().lower() != "success":
                continue
            created_programs.append(dict(payload))
            program = dict(payload.get("program", {})) if isinstance(payload.get("program", {}), dict) else {}
            program_id = str(program.get("program_id", "") or "").strip()
            if program_id:
                program_ids.append(program_id)
        portfolio_id = f"benchportfolio-test-{len(self.desktop_evaluation_lab_portfolios_items) + 1}"
        created_at = datetime.now(timezone.utc).isoformat()
        portfolio = {
            "portfolio_id": portfolio_id,
            "status": "ready",
            "label": base_label,
            "source": str(source or "action_control_panel"),
            "created_at": created_at,
            "updated_at": created_at,
            "filters": dict(lab.get("filters", {})),
            "focus_summary": list(native_targets.get("focus_summary", [])),
            "program_ids": list(program_ids),
            "target_apps": list(target_apps),
            "app_targets": list(target_apps),
            "wave_runs": [],
            "wave_count": 0,
            "completed_wave_count": 0,
            "stable_wave_count": 0,
            "regression_wave_count": 0,
            "stable_wave_streak": 0,
            "regression_wave_streak": 0,
            "latest_wave_status": "",
            "latest_wave_stop_reason": "",
            "latest_wave_executed_at": "",
            "latest_wave_executed_program_count": 0,
            "latest_wave_executed_campaign_count": 0,
            "latest_wave_executed_sweep_count": 0,
            "latest_wave_weighted_score": 0.0,
            "latest_wave_weighted_pass_rate": 0.0,
            "latest_wave_trend_direction": "",
            "history_direction": "",
            "trend_summary": {},
            "lab_snapshot": dict(lab),
            "native_targets_snapshot": dict(native_targets),
            "guidance_snapshot": dict(guidance),
        }
        portfolio = self._desktop_evaluation_refresh_portfolio_row(portfolio)
        self.desktop_evaluation_lab_portfolios_items.insert(0, portfolio)
        self.desktop_evaluation_lab_portfolios_items = self.desktop_evaluation_lab_portfolios_items[:8]
        return {
            "status": "success",
            "portfolio": dict(portfolio),
            "created_programs": created_programs,
            "created_program_count": len(created_programs),
            "created_campaign_count": sum(
                int(item.get("created_campaign_count", 0) or 0)
                for item in created_programs
                if isinstance(item, dict)
            ),
            "created_session_count": sum(
                int(item.get("created_session_count", 0) or 0)
                for item in created_programs
                if isinstance(item, dict)
            ),
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_run_lab_portfolio_cycle(
        self,
        *,
        portfolio_id: str = "",
        max_programs: int = 3,
        max_campaigns_per_program: int = 3,
        max_sweeps_per_campaign: int = 2,
        max_sessions: int = 3,
        max_replays_per_session: int = 2,
        history_limit: int = 8,
        stop_on_stable: bool = True,
    ) -> Dict[str, Any]:
        normalized_max_programs = max(1, int(max_programs or 3))
        selected: Dict[str, Any] | None = None
        selected_index = -1
        for index, item in enumerate(self.desktop_evaluation_lab_portfolios_items):
            if str(item.get("portfolio_id", "") or "").strip() == str(portfolio_id or "").strip():
                selected = self._desktop_evaluation_refresh_portfolio_row(dict(item))
                selected_index = index
                break
        if selected is None:
            return {"status": "error", "message": "benchmark lab portfolio not found"}
        filters = dict(selected.get("filters", {})) if isinstance(selected.get("filters", {}), dict) else {}
        portfolio_program_ids = [
            str(item).strip()
            for item in selected.get("program_ids", [])
            if str(item).strip()
        ] if isinstance(selected.get("program_ids", []), list) else []
        current_programs = [
            self._desktop_evaluation_refresh_program_row(dict(item))
            for item in self.desktop_evaluation_lab_programs_items
            if str(item.get("program_id", "") or "").strip() in portfolio_program_ids
        ]
        represented_apps = {
            str(app_name).strip().lower()
            for item in current_programs
            for app_name in item.get("target_apps", [])
            if str(app_name).strip()
        }
        app_targets = [
            str(item).strip()
            for item in selected.get("target_apps", selected.get("app_targets", []))
            if str(item).strip()
        ] if isinstance(selected.get("target_apps", selected.get("app_targets", [])), list) else []
        created_programs: list[Dict[str, Any]] = []
        for target_app in app_targets:
            if target_app.strip().lower() in represented_apps:
                continue
            if len(current_programs) + len(created_programs) >= max(normalized_max_programs, len(current_programs)):
                break
            payload = self.desktop_evaluation_create_lab_program(
                scenario_name=str(filters.get("scenario_name", "") or ""),
                pack=str(filters.get("pack", "") or ""),
                category=str(filters.get("category", "") or ""),
                capability=str(filters.get("capability", "") or ""),
                risk_level=str(filters.get("risk_level", "") or ""),
                autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
                mission_family=str(filters.get("mission_family", "") or ""),
                app_name=target_app,
                limit=int(filters.get("limit", 200) or 200),
                history_limit=history_limit,
                source="benchmark_portfolio_cycle",
                label=f"{str(selected.get('label', '') or 'replay portfolio').strip()} / {target_app}",
                max_campaigns=max(1, int(max_campaigns_per_program or 3)),
                max_sessions_per_campaign=max(1, int(max_sessions or 3)),
            )
            if str(payload.get("status", "") or "").strip().lower() != "success":
                continue
            created_programs.append(dict(payload))
            program = dict(payload.get("program", {})) if isinstance(payload.get("program", {}), dict) else {}
            program_id = str(program.get("program_id", "") or "").strip()
            if program_id and program_id not in portfolio_program_ids:
                portfolio_program_ids.append(program_id)
                current_programs.append(self._desktop_evaluation_refresh_program_row(program))
        ranked_programs = sorted(
            current_programs,
            key=lambda item: (
                1 if str(item.get("status", "") or "").strip().lower() == "attention" else 0,
                int(item.get("attention_campaign_count", 0) or 0),
                int(item.get("pending_campaign_count", 0) or 0),
                int(item.get("pending_session_count", 0) or 0),
                int(item.get("pending_app_target_count", 0) or 0),
                float(item.get("program_pressure_score", 0.0) or 0.0),
            ),
            reverse=True,
        )[:normalized_max_programs]
        results: list[Dict[str, Any]] = []
        for program in ranked_programs:
            program_id_value = str(program.get("program_id", "") or "").strip()
            if not program_id_value:
                continue
            results.append(
                self.desktop_evaluation_run_lab_program_cycle(
                    program_id=program_id_value,
                    max_campaigns=max_campaigns_per_program,
                    max_sweeps_per_campaign=max_sweeps_per_campaign,
                    max_sessions=max_sessions,
                    max_replays_per_session=max_replays_per_session,
                    history_limit=history_limit,
                    stop_on_stable=stop_on_stable,
                )
            )
        refreshed_programs = [
            self._desktop_evaluation_refresh_program_row(dict(item))
            for item in self.desktop_evaluation_lab_programs_items
            if str(item.get("program_id", "") or "").strip() in portfolio_program_ids
        ]
        selected["program_ids"] = list(portfolio_program_ids)
        selected["target_apps"] = list(
            dict.fromkeys(
                [
                    *app_targets,
                    *[
                        app_name
                        for item in refreshed_programs
                        for app_name in item.get("target_apps", [])
                        if str(app_name).strip()
                    ],
                ]
            )
        )
        lab = self.desktop_evaluation_lab(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        native_targets = self.desktop_evaluation_native_targets(
            scenario_name=str(filters.get("scenario_name", "") or ""),
            pack=str(filters.get("pack", "") or ""),
            category=str(filters.get("category", "") or ""),
            capability=str(filters.get("capability", "") or ""),
            risk_level=str(filters.get("risk_level", "") or ""),
            autonomy_tier=str(filters.get("autonomy_tier", "") or ""),
            mission_family=str(filters.get("mission_family", "") or ""),
            app_name=str(filters.get("app", filters.get("app_name", "")) or ""),
            limit=int(filters.get("limit", 200) or 200),
            history_limit=history_limit,
        )
        guidance = self.desktop_evaluation_guidance()
        stable = bool(results) and all(bool(dict(item.get("cycle", {})).get("stable", False)) for item in results)
        trend_direction = (
            "regression"
            if any(
                str(dict(item.get("program", {})).get("latest_cycle_status", "") or "").strip().lower()
                in {"regression", "failed", "error"}
                for item in results
            )
            else str(dict(lab.get("history_trend", {})).get("direction", "") or "").strip().lower()
        )
        wave_row = {
            "wave_id": f"{str(selected.get('portfolio_id', '') or portfolio_id).strip()}-wave-{int(selected.get('wave_count', 0) or 0) + 1}",
            "recorded_at": datetime.now(timezone.utc).isoformat(),
            "executed_at": datetime.now(timezone.utc).isoformat(),
            "status": "success" if results else "idle",
            "stop_reason": "stable" if stable and stop_on_stable else ("idle" if not results else "program_budget_reached"),
            "stable": stable,
            "executed_program_count": len(results),
            "executed_campaign_count": sum(
                int(dict(item.get("cycle", {})).get("executed_campaign_count", 0) or 0)
                for item in results
            ),
            "executed_sweep_count": sum(
                int(dict(item.get("cycle", {})).get("executed_sweep_count", 0) or 0)
                for item in results
            ),
            "created_program_count": len(created_programs),
            "created_campaign_count": sum(
                int(item.get("created_campaign_count", 0) or 0)
                for item in created_programs
                if isinstance(item, dict)
            ),
            "created_session_count": sum(
                int(item.get("created_session_count", 0) or 0)
                for item in created_programs
                if isinstance(item, dict)
            ),
            "weighted_score": round(
                float(dict(lab.get("latest_summary", {})).get("weighted_score", 0.0) or 0.0),
                6,
            ),
            "weighted_pass_rate": round(
                float(dict(lab.get("latest_summary", {})).get("weighted_pass_rate", 0.0) or 0.0),
                6,
            ),
            "trend_direction": trend_direction,
            "portfolio_priority": "critical" if trend_direction == "regression" else "elevated",
        }
        selected.setdefault("wave_runs", [])
        if not isinstance(selected.get("wave_runs", []), list):
            selected["wave_runs"] = []
        selected["wave_runs"].append(wave_row)
        selected["lab_snapshot"] = dict(lab)
        selected["native_targets_snapshot"] = dict(native_targets)
        selected["guidance_snapshot"] = dict(guidance)
        selected = self._desktop_evaluation_refresh_portfolio_row(selected)
        if 0 <= selected_index < len(self.desktop_evaluation_lab_portfolios_items):
            self.desktop_evaluation_lab_portfolios_items[selected_index] = selected
        return {
            "status": "success",
            "portfolio": dict(selected),
            "wave": dict(wave_row),
            "results": results,
            "created_programs": created_programs,
            "created_program_count": len(created_programs),
            "created_campaign_count": sum(
                int(item.get("created_campaign_count", 0) or 0)
                for item in created_programs
                if isinstance(item, dict)
            ),
            "created_session_count": sum(
                int(item.get("created_session_count", 0) or 0)
                for item in created_programs
                if isinstance(item, dict)
            ),
            "lab": dict(lab),
            "native_targets": dict(native_targets),
            "guidance": dict(guidance),
        }

    def desktop_evaluation_run_lab_portfolio_campaign(
        self,
        *,
        portfolio_id: str = "",
        max_waves: int = 2,
        max_programs: int = 3,
        max_campaigns_per_program: int = 3,
        max_sweeps_per_campaign: int = 2,
        max_sessions: int = 3,
        max_replays_per_session: int = 2,
        history_limit: int = 8,
        stop_on_stable: bool = True,
        stop_on_regression: bool = True,
    ) -> Dict[str, Any]:
        normalized_max_waves = max(1, int(max_waves or 2))
        selected_index = -1
        selected: Dict[str, Any] | None = None
        for index, item in enumerate(self.desktop_evaluation_lab_portfolios_items):
            if str(item.get("portfolio_id", "") or "").strip() == str(portfolio_id or "").strip():
                selected_index = index
                selected = self._desktop_evaluation_refresh_portfolio_row(dict(item))
                break
        if selected is None:
            return {"status": "error", "message": "benchmark lab portfolio not found"}

        wave_results: list[Dict[str, Any]] = []
        stable_wave_count = 0
        regression_wave_count = 0
        stop_reason = "max_waves_reached"
        status = "success"
        for _ in range(normalized_max_waves):
            cycle = self.desktop_evaluation_run_lab_portfolio_cycle(
                portfolio_id=str(selected.get("portfolio_id", "") or portfolio_id).strip(),
                max_programs=max_programs,
                max_campaigns_per_program=max_campaigns_per_program,
                max_sweeps_per_campaign=max_sweeps_per_campaign,
                max_sessions=max_sessions,
                max_replays_per_session=max_replays_per_session,
                history_limit=history_limit,
                stop_on_stable=stop_on_stable,
            )
            wave_results.append(cycle)
            if str(cycle.get("status", "") or "").strip().lower() == "error":
                status = "partial"
                stop_reason = "wave_error"
                break
            wave = dict(cycle.get("wave", {})) if isinstance(cycle.get("wave", {}), dict) else {}
            portfolio = dict(cycle.get("portfolio", {})) if isinstance(cycle.get("portfolio", {}), dict) else {}
            wave_stop_reason = str(wave.get("stop_reason", "") or "").strip().lower()
            latest_wave_status = str(portfolio.get("latest_wave_status", wave.get("trend_direction", "")) or "").strip().lower()
            if bool(wave.get("stable", False)) or wave_stop_reason == "stable":
                stable_wave_count += 1
                if stop_on_stable:
                    stop_reason = "stable"
                    break
            if latest_wave_status in {"regression", "failed", "error"} or wave_stop_reason in {"regression_detected", "wave_error"}:
                regression_wave_count += 1
                if stop_on_regression:
                    status = "partial"
                    stop_reason = "regression_detected"
                    break
            if wave_stop_reason == "idle":
                status = "partial"
                stop_reason = "no_progress"
                break

        selected = self._desktop_evaluation_refresh_portfolio_row(
            dict(self.desktop_evaluation_lab_portfolios_items[selected_index])
        )
        campaign_row = {
            "campaign_id": f"{str(selected.get('portfolio_id', '') or portfolio_id).strip()}-campaign-{int(selected.get('completed_campaign_count', 0) or 0) + 1}",
            "recorded_at": datetime.now(timezone.utc).isoformat(),
            "executed_at": datetime.now(timezone.utc).isoformat(),
            "status": "stable" if stop_reason == "stable" else status,
            "stop_reason": stop_reason,
            "executed_wave_count": len(wave_results),
            "stable_wave_count": stable_wave_count,
            "regression_wave_count": regression_wave_count,
            "executed_program_count": sum(
                int(dict(item.get("wave", {})).get("executed_program_count", 0) or 0)
                for item in wave_results
                if isinstance(item, dict)
            ),
            "executed_campaign_count": sum(
                int(dict(item.get("wave", {})).get("executed_campaign_count", 0) or 0)
                for item in wave_results
                if isinstance(item, dict)
            ),
            "executed_sweep_count": sum(
                int(dict(item.get("wave", {})).get("executed_sweep_count", 0) or 0)
                for item in wave_results
                if isinstance(item, dict)
            ),
            "weighted_score": round(
                float(dict(dict(wave_results[-1] if wave_results else {}).get("wave", {})).get("weighted_score", 0.0) or 0.0),
                6,
            ),
            "weighted_pass_rate": round(
                float(dict(dict(wave_results[-1] if wave_results else {}).get("wave", {})).get("weighted_pass_rate", 0.0) or 0.0),
                6,
            ),
            "trend_direction": str(
                dict(dict(wave_results[-1] if wave_results else {}).get("wave", {})).get("trend_direction", "")
                or ""
            ).strip().lower(),
        }
        if not isinstance(selected.get("campaign_runs", []), list):
            selected["campaign_runs"] = []
        selected.setdefault("campaign_runs", [])
        selected["campaign_runs"].append(campaign_row)
        selected = self._desktop_evaluation_refresh_portfolio_row(selected)
        if 0 <= selected_index < len(self.desktop_evaluation_lab_portfolios_items):
            self.desktop_evaluation_lab_portfolios_items[selected_index] = selected
        latest_lab = dict(wave_results[-1].get("lab", {})) if wave_results and isinstance(wave_results[-1], dict) else {}
        latest_native_targets = dict(wave_results[-1].get("native_targets", {})) if wave_results and isinstance(wave_results[-1], dict) else {}
        latest_guidance = dict(wave_results[-1].get("guidance", {})) if wave_results and isinstance(wave_results[-1], dict) else {}
        return {
            "status": status,
            "portfolio": dict(selected),
            "campaign": dict(campaign_row),
            "wave_results": wave_results,
            "executed_wave_count": len(wave_results),
            "stable_wave_count": stable_wave_count,
            "regression_wave_count": regression_wave_count,
            "stop_reason": stop_reason,
            "lab": latest_lab,
            "native_targets": latest_native_targets,
            "guidance": latest_guidance,
        }

    def desktop_evaluation_campaign_supervisor_status(self, *, history_limit: int = 6) -> Dict[str, Any]:
        payload = dict(self.desktop_evaluation_campaign_daemon_state)
        payload["campaigns"] = self.desktop_evaluation_lab_campaigns(
            limit=max(1, int(history_limit or 6)),
            status=str(payload.get("campaign_status", "") or "").strip(),
        )
        payload["history_count"] = len(self.desktop_evaluation_campaign_daemon_history_items)
        payload["latest_history_run"] = (
            dict(self.desktop_evaluation_campaign_daemon_history_items[-1])
            if self.desktop_evaluation_campaign_daemon_history_items
            else {}
        )
        payload["history"] = self.desktop_evaluation_campaign_supervisor_history(limit=history_limit)
        return payload

    def desktop_evaluation_campaign_supervisor_history(
        self,
        *,
        limit: int = 12,
        status: str = "",
        source: str = "",
    ) -> Dict[str, Any]:
        normalized_status = str(status or "").strip().lower()
        normalized_source = str(source or "").strip().lower()
        items = [
            dict(item)
            for item in self.desktop_evaluation_campaign_daemon_history_items
            if (
                not normalized_status
                or str(item.get("status", "") or "").strip().lower() == normalized_status
            )
            and (
                not normalized_source
                or str(item.get("source", "") or "").strip().lower() == normalized_source
            )
        ]
        limited = items[-max(1, int(limit or 12)) :]
        return {
            "status": "success",
            "count": len(limited),
            "total": len(items),
            "limit": max(1, int(limit or 12)),
            "filters": {"status": normalized_status, "source": normalized_source},
            "items": limited,
            "latest_run": dict(limited[-1]) if limited else {},
        }

    def reset_desktop_evaluation_campaign_supervisor_history(
        self,
        *,
        status: str = "",
        source: str = "",
        history_response_limit: int = 6,
    ) -> Dict[str, Any]:
        normalized_status = str(status or "").strip().lower()
        normalized_source = str(source or "").strip().lower()
        before = len(self.desktop_evaluation_campaign_daemon_history_items)
        if normalized_status or normalized_source:
            self.desktop_evaluation_campaign_daemon_history_items = [
                item
                for item in self.desktop_evaluation_campaign_daemon_history_items
                if not (
                    (not normalized_status or str(item.get("status", "") or "").strip().lower() == normalized_status)
                    and (not normalized_source or str(item.get("source", "") or "").strip().lower() == normalized_source)
                )
            ]
        else:
            self.desktop_evaluation_campaign_daemon_history_items = []
        self.desktop_evaluation_campaign_daemon_state["history_count"] = len(
            self.desktop_evaluation_campaign_daemon_history_items
        )
        self.desktop_evaluation_campaign_daemon_state["latest_history_run"] = (
            dict(self.desktop_evaluation_campaign_daemon_history_items[-1])
            if self.desktop_evaluation_campaign_daemon_history_items
            else {}
        )
        self.desktop_evaluation_campaign_daemon_state["updated_at"] = datetime.now(timezone.utc).isoformat()
        return {
            "status": "success",
            "removed_count": max(0, before - len(self.desktop_evaluation_campaign_daemon_history_items)),
            "remaining_count": len(self.desktop_evaluation_campaign_daemon_history_items),
            "filters": {"status": normalized_status, "source": normalized_source},
            "latest_run": dict(self.desktop_evaluation_campaign_daemon_state["latest_history_run"])
            if isinstance(self.desktop_evaluation_campaign_daemon_state.get("latest_history_run", {}), dict)
            else {},
            "supervisor": self.desktop_evaluation_campaign_supervisor_status(history_limit=history_response_limit),
        }

    def configure_desktop_evaluation_campaign_supervisor(
        self,
        *,
        enabled: bool | None = None,
        interval_s: float | None = None,
        max_campaigns: int | None = None,
        max_sweeps_per_campaign: int | None = None,
        max_sessions: int | None = None,
        max_replays_per_session: int | None = None,
        history_limit: int | None = None,
        campaign_status: str | None = None,
        pack: str | None = None,
        app_name: str | None = None,
        source: str = "manual",
        history_response_limit: int = 6,
    ) -> Dict[str, Any]:
        if enabled is not None:
            self.desktop_evaluation_campaign_daemon_state["enabled"] = bool(enabled)
        if interval_s is not None:
            self.desktop_evaluation_campaign_daemon_state["interval_s"] = float(interval_s)
        if max_campaigns is not None:
            self.desktop_evaluation_campaign_daemon_state["max_campaigns"] = int(max_campaigns)
        if max_sweeps_per_campaign is not None:
            self.desktop_evaluation_campaign_daemon_state["max_sweeps_per_campaign"] = int(max_sweeps_per_campaign)
        if max_sessions is not None:
            self.desktop_evaluation_campaign_daemon_state["max_sessions"] = int(max_sessions)
        if max_replays_per_session is not None:
            self.desktop_evaluation_campaign_daemon_state["max_replays_per_session"] = int(max_replays_per_session)
        if history_limit is not None:
            self.desktop_evaluation_campaign_daemon_state["history_limit"] = int(history_limit)
        if campaign_status is not None:
            self.desktop_evaluation_campaign_daemon_state["campaign_status"] = str(campaign_status or "").strip()
        if pack is not None:
            self.desktop_evaluation_campaign_daemon_state["pack"] = str(pack or "").strip()
        if app_name is not None:
            self.desktop_evaluation_campaign_daemon_state["app_name"] = str(app_name or "").strip()
        self.desktop_evaluation_campaign_daemon_state["last_config_source"] = str(source or "manual").strip()
        self.desktop_evaluation_campaign_daemon_state["updated_at"] = datetime.now(timezone.utc).isoformat()
        return self.desktop_evaluation_campaign_supervisor_status(history_limit=history_response_limit)

    def trigger_desktop_evaluation_campaign_supervisor(
        self,
        *,
        max_campaigns: int | None = None,
        max_sweeps_per_campaign: int | None = None,
        max_sessions: int | None = None,
        max_replays_per_session: int | None = None,
        history_limit: int | None = None,
        campaign_status: str | None = None,
        pack: str | None = None,
        app_name: str | None = None,
        source: str = "manual",
        history_response_limit: int = 6,
    ) -> Dict[str, Any]:
        effective_max_campaigns = int(max_campaigns or self.desktop_evaluation_campaign_daemon_state.get("max_campaigns", 2) or 2)
        effective_max_sweeps = int(
            max_sweeps_per_campaign or self.desktop_evaluation_campaign_daemon_state.get("max_sweeps_per_campaign", 2) or 2
        )
        effective_max_sessions = int(max_sessions or self.desktop_evaluation_campaign_daemon_state.get("max_sessions", 3) or 3)
        effective_max_replays = int(
            max_replays_per_session
            or self.desktop_evaluation_campaign_daemon_state.get("max_replays_per_session", 2)
            or 2
        )
        effective_history_limit = int(history_limit or self.desktop_evaluation_campaign_daemon_state.get("history_limit", 8) or 8)
        effective_status = str(
            campaign_status
            if campaign_status is not None
            else self.desktop_evaluation_campaign_daemon_state.get("campaign_status", "")
            or ""
        ).strip()
        effective_pack = str(
            pack if pack is not None else self.desktop_evaluation_campaign_daemon_state.get("pack", "") or ""
        ).strip().lower()
        effective_app = str(
            app_name if app_name is not None else self.desktop_evaluation_campaign_daemon_state.get("app_name", "") or ""
        ).strip().lower()
        campaign_rows = [
            dict(item)
            for item in self.desktop_evaluation_lab_campaigns_items
            if not effective_status or str(item.get("status", "") or "").strip().lower() == effective_status.lower()
        ]
        if effective_pack:
            campaign_rows = [
                item
                for item in campaign_rows
                if str(dict(item.get("filters", {})).get("pack", "") or "").strip().lower() == effective_pack
            ]
        if effective_app:
            campaign_rows = [
                item
                for item in campaign_rows
                if effective_app
                in {
                    str(dict(item.get("filters", {})).get("app", dict(item.get("filters", {})).get("app_name", "")) or "")
                    .strip()
                    .lower(),
                    *[
                        str(value).strip().lower()
                        for value in item.get("target_apps", item.get("app_targets", []))
                        if str(value).strip()
                    ],
                }
            ]
        ranked = sorted(
            campaign_rows,
            key=lambda item: (
                int(item.get("attention_session_count", 0) or 0),
                int(item.get("pending_session_count", 0) or 0),
                int(item.get("pending_app_target_count", 0) or 0),
                int(item.get("long_horizon_pending_count", 0) or 0),
                int(item.get("regression_cycle_count", 0) or 0),
            ),
            reverse=True,
        )[: max(1, effective_max_campaigns)]
        results: list[Dict[str, Any]] = []
        for campaign in ranked:
            sweep = self.desktop_evaluation_run_lab_campaign_cycle(
                campaign_id=str(campaign.get("campaign_id", "") or "").strip(),
                max_sweeps=effective_max_sweeps,
                max_sessions=effective_max_sessions,
                max_replays_per_session=effective_max_replays,
                history_limit=effective_history_limit,
            )
            results.append(sweep)
        now_iso = datetime.now(timezone.utc).isoformat()
        self.desktop_evaluation_campaign_daemon_state["run_count"] = int(self.desktop_evaluation_campaign_daemon_state.get("run_count", 0) or 0) + 1
        self.desktop_evaluation_campaign_daemon_state["manual_trigger_count"] = (
            int(self.desktop_evaluation_campaign_daemon_state.get("manual_trigger_count", 0) or 0) + 1
        )
        self.desktop_evaluation_campaign_daemon_state["last_trigger_source"] = str(source or "manual").strip()
        self.desktop_evaluation_campaign_daemon_state["last_trigger_at"] = now_iso
        self.desktop_evaluation_campaign_daemon_state["last_tick_at"] = now_iso
        self.desktop_evaluation_campaign_daemon_state["last_success_at"] = now_iso
        self.desktop_evaluation_campaign_daemon_state["last_result_status"] = "success" if results else "idle"
        self.desktop_evaluation_campaign_daemon_state["last_result_message"] = (
            f"campaign watchdog executed {len(results)} campaign(s)"
            if results
            else "campaign watchdog found no executable replay campaigns"
        )
        self.desktop_evaluation_campaign_daemon_state["last_summary"] = {
            "status": self.desktop_evaluation_campaign_daemon_state["last_result_status"],
            "targeted_campaign_count": len(ranked),
            "executed_campaign_count": len(results),
            "executed_sweep_count": sum(
                int(dict(item.get("cycle", {})).get("executed_sweep_count", 0) or 0) for item in results
            ),
            "stable_campaign_count": sum(1 for item in results if bool(dict(item.get("cycle", {})).get("stable", False))),
            "regression_campaign_count": sum(
                1
                for item in results
                if str(dict(item.get("campaign", {})).get("latest_sweep_regression_status", "") or "").strip().lower() == "regression"
            ),
            "pending_session_count": sum(
                int(dict(item.get("campaign", {})).get("pending_session_count", 0) or 0) for item in results
            ),
            "attention_session_count": sum(
                int(dict(item.get("campaign", {})).get("attention_session_count", 0) or 0) for item in results
            ),
            "pending_app_target_count": sum(
                int(dict(item.get("campaign", {})).get("pending_app_target_count", 0) or 0) for item in results
            ),
            "long_horizon_pending_count": sum(
                int(dict(item.get("campaign", {})).get("long_horizon_pending_count", 0) or 0) for item in results
            ),
            "error_count": 0,
            "latest_campaign_label": str(dict(results[0].get("campaign", {})).get("label", "") or "").strip() if results else "",
            "auto_created_campaign_count": 0,
            "cycle_stop_reason_counts": {
                str(dict(item.get("cycle", {})).get("stop_reason", "unknown") or "unknown"): 1
                for item in results
            },
        }
        history_entry = {
            "recorded_at": now_iso,
            "source": str(source or "manual").strip().lower() or "manual",
            "status": self.desktop_evaluation_campaign_daemon_state["last_result_status"],
            "message": self.desktop_evaluation_campaign_daemon_state["last_result_message"],
            "duration_ms": 0.0,
            "filters": {
                "campaign_status": effective_status,
                "pack": effective_pack,
                "app_name": effective_app,
            },
            **dict(self.desktop_evaluation_campaign_daemon_state["last_summary"]),
        }
        self.desktop_evaluation_campaign_daemon_history_items.append(history_entry)
        self.desktop_evaluation_campaign_daemon_history_items = self.desktop_evaluation_campaign_daemon_history_items[
            -max(1, int(self.desktop_evaluation_campaign_daemon_state.get("history_limit", 8) or 8)) :
        ]
        self.desktop_evaluation_campaign_daemon_state["history_count"] = len(
            self.desktop_evaluation_campaign_daemon_history_items
        )
        self.desktop_evaluation_campaign_daemon_state["latest_history_run"] = (
            dict(self.desktop_evaluation_campaign_daemon_history_items[-1])
            if self.desktop_evaluation_campaign_daemon_history_items
            else {}
        )
        self.desktop_evaluation_campaign_daemon_state["updated_at"] = now_iso
        return {
            "status": self.desktop_evaluation_campaign_daemon_state["last_result_status"],
            "message": self.desktop_evaluation_campaign_daemon_state["last_result_message"],
            "result": {
                "status": self.desktop_evaluation_campaign_daemon_state["last_result_status"],
                "message": self.desktop_evaluation_campaign_daemon_state["last_result_message"],
                "targeted_campaign_count": len(ranked),
                "executed_campaign_count": len(results),
                "results": results,
            },
            "supervisor": self.desktop_evaluation_campaign_supervisor_status(history_limit=history_response_limit),
        }

