    assert status == 200
    assert cancelled["status"] == "success"
    assert cancelled["mission_id"] == mission_id

    status, fetched = request_json("GET", f"{base_url}/missions/{mission_id}")
    assert status == 200
    assert fetched["mission"]["status"] == "cancelled"


